@app.post("/tokens", response_model=TokenData, tags=["Token Management"])
async def create_token(
    request: TokenCreateRequest,
    token_service: TokenValidationService = Depends(get_token_service),
):
    """
    Store a token in Redis cache.
    In production, tokens would be issued by an OAuth 2.0 authorization server.
    This endpoint is for demonstration/testing purposes.
    """
    token_data = await token_service.store_token(
        token=request.token,
        user_id=request.user_id,
        email=request.email,
        scopes=request.scopes,
        ttl_seconds=request.ttl_seconds,
    )
    return token_data


@app.delete("/tokens/{token}", tags=["Token Management"])
async def revoke_token(
    token: str,
    token_service: TokenValidationService = Depends(get_token_service),
):
    """Revoke a token by removing it from Redis cache."""
    revoked = await token_service.revoke_token(token)
    if not revoked:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail="Token not found",
        )
    return {"message": "Token revoked successfully"}


